// Lista básica de nomes e sobrenomes (pode expandir depois)
const nomes = [
  "João", "Maria", "Pedro", "Ana", "Lucas",
  "Beatriz", "Carlos", "Juliana", "Rafael", "Fernanda"
];

const sobrenomes = [
  "Silva", "Santos", "Oliveira", "Souza", "Lima",
  "Costa", "Pereira", "Almeida", "Ferreira", "Rodrigues"
];

// Função para pegar item aleatório
function randomItem(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

// Gera nome completo
const nome = randomItem(nomes);
const sobrenome = randomItem(sobrenomes);

const nomeCompleto = `${nome} ${sobrenome}`;

// Retorno no padrão do n8n
return [
  {
    json: {
      nome: nomeCompleto
    }
  }
];

